#!/usr/bin/env bash

set -euo pipefail

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"

FORBIDDEN=(
    "Tai""ls"
    "tails"".""net"
    "tails""-""stable"
    "Generated by ""AI"
    "AI""-""assisted"
    "Built with ""AI"
)

TARGETS=(
    "${ROOT_DIR}/README.md"
    "${ROOT_DIR}/build"
    "${ROOT_DIR}/config"
    "${ROOT_DIR}/hooks"
    "${ROOT_DIR}/apps"
    "${ROOT_DIR}/tests"
    "${ROOT_DIR}/docs"
)

for token in "${FORBIDDEN[@]}"; do
    if grep -RIn --exclude-dir=__pycache__ --exclude="*.pyc" --exclude="verify-no-leaks.sh" -- "${token}" "${TARGETS[@]}" >/dev/null; then
        echo "forbidden string found: ${token}" >&2
        grep -RIn --exclude-dir=__pycache__ --exclude="*.pyc" --exclude="verify-no-leaks.sh" -- "${token}" "${TARGETS[@]}" >&2
        exit 1
    fi
done

echo "No forbidden naming leaks found."
